// 功能：處理答題記錄，精準找出答錯的題目 (兼容 Object/Array)
const inputData = $input.first().json.body;
const answers = inputData.answers;
const questions = inputData.questions;
const wrongQuestions = [];

// 統一處理 Object 或 Array
const keys = Object.keys(answers);

keys.forEach(index => {
  const answer = answers[index];
  const question = questions[index];

  if (question) {
    // 優先使用前端傳來的 isCorrect 標記，若無則比對 originalIndex
    // 這樣可以避免因為選項打亂導致後端判斷錯誤
    const isUserCorrect = (answer.isCorrect !== undefined) 
      ? answer.isCorrect 
      : (answer.originalIndex === question.correct_answer_index);

    if (!isUserCorrect) {
      wrongQuestions.push({
        user_id: inputData.userId,
        question_id: question.question_id || `Q${parseInt(index) + 1}`,
        database_type: inputData.databaseType || 'ipas',
        topic: question.topic || '未分類',
        subtopic: question.subtopic || '未分類',
        question_text: question.question,
        correct_answer: question.correct_answer_letter, // 這裡會是打亂後正確的字母
        user_answer: answer.answer,
        answered_at: answer.timestamp || new Date().toISOString()
      });
    }
  }
});

return wrongQuestions.map(q => ({ json: q }));

