    const params = { ...data };
    delete params.CheckMacValue;

    // 按 key 排序
    const sortedKeys = Object.keys(params).sort();

    // 組成字串
    let checkStr = `HashKey=${hashKey}&`;
    for (const key of sortedKeys) {
        checkStr += `${key}=${params[key]}&`;
    }
    checkStr += `HashIV=${hashIv}`;

    // URL encode → 轉小寫 → MD5 → 轉大寫
    checkStr = ecpayUrlEncode(checkStr);
    checkStr = checkStr.toLowerCase();
    const calculatedCheckMac = md5(checkStr).toUpperCase();

    console.log('收到的 CheckMacValue:', receivedCheckMac);
    console.log('計算的 CheckMacValue:', calculatedCheckMac);

    return receivedCheckMac === calculatedCheckMac;
}

